    if env:
        return env, None

    on_lan = list_robot_lan_interfaces()

    if requested:
        req = requested.strip()
        if iface_exists(req):
            return req, None
        if len(on_lan) == 1:
            name, ip = on_lan[0]
            return (
                name,
                f"Note: {req!r} is not on this PC — using {name} ({ip}/24).\n"
                f"  export {env_var}={name}",
            )
        return req, None

    if len(on_lan) == 1:
        name, ip = on_lan[0]
        return (
            name,
            f"Note: no interface argument — using {name} ({ip}/24) on the robot LAN.\n"
            f"  export {env_var}={name}",
